async function loadMedia(){const e=await fetch("media/media.json"),i=await e.json();let o="";for(let e=0;e<i.length;e++){let t="",a="";"game"===i[e].type?(t="games",a="gamepad"):"book"===i[e].type?(t="books",a="book"):"film"===i[e].type?(t="films",a="video"):"show"===i[e].type?(t="shows",a="television"):(t="none",a="question-circle-o"),i[e].imbibed?t+=" imbibed":t+=" not-imbibed",i[e].favorite&&(t+=" favorites"),o+='<div class="col-lg-3 col-md-4 '+t+'"><div class="media-item"><div class="media-img"><span style="color: #008080;"><i class="icon-'+a+'"></i></span></div><div class="product-content text-center py-3"><h5 class="card-title">'+i[e].name+"</h5></div></div></div>"}document.getElementById("media-filter").innerHTML=o;var t=document.querySelector("#media-filter");iso=new Isotope(t,{itemSelector:".col-lg-3",layoutMode:"fitRows"})}window.addEventListener("DOMContentLoaded",loadMedia);